from dataclasses import dataclass
from typing import Callable


@dataclass
class Production:
    """An if-then rule in SOAR production memory."""
    name: str
    lhs: Callable[[WorkingMemory], bool]    # left-hand side: conditions
    rhs: Callable[[WorkingMemory], None]    # right-hand side: WM changes
    preference: str = "indifferent"         # "better", "worse", "required", etc.


class ProductionMemory:
    """Stores all productions; fires eligible ones during elaboration."""

    def __init__(self):
        self._productions: list[Production] = []

    def add(self, production: Production) -> None:
        self._productions.append(production)

    def match(self, wm: WorkingMemory) -> list[Production]:
        """Return all productions whose conditions are satisfied."""
        return [p for p in self._productions if p.lhs(wm)]

    def elaborate(self, wm: WorkingMemory) -> int:
        """Fire all matching productions until quiescence. Returns fired count."""
        fired = 0
        while True:
            matching = self.match(wm)
            if not matching:
                break
            for prod in matching:
                prod.rhs(wm)
                fired += 1
            # In practice SOAR uses the Rete algorithm to avoid re-checking
            break  # simplified: one pass
        return fired


# Production: if state goal is "on-A-B" and A is on table → propose operator "move-A-to-B"
def propose_move(wm: WorkingMemory) -> bool:
    goal_match = wm.query(attr="goal", value="on-A-B")
    on_table   = wm.query(attr="on",   value="A-table")
    return bool(goal_match and on_table)

def apply_propose(wm: WorkingMemory) -> None:
    wm.add("O1", "name", "move-A-to-B")
    wm.add("S1", "operator", "O1")

pm = ProductionMemory()
pm.add(Production("propose-move-A-to-B", propose_move, apply_propose))

from dataclasses import dataclass, field


class SOARAgent:
    """Simplified SOAR decision cycle without the full Rete engine."""

    def __init__(self):
        self.wm = WorkingMemory()
        self.pm = ProductionMemory()
        self.actions_taken: list[str] = []
        self.chunk_count = 0

    # Phase 1: input
    def input_phase(self, percepts: dict[str, str]) -> None:
        for attr, value in percepts.items():
            self.wm.add("S1", attr, value)

    # Phase 2: elaboration (run productions to quiescence)
    def elaboration_phase(self) -> int:
        return self.pm.elaborate(self.wm)

    # Phase 3: decision — choose one operator from proposals
    def decision_phase(self) -> str | None:
        proposals = self.wm.query(id="S1", attr="operator")
        if not proposals:
            return None  # no operator proposed → impasse
        # Simplification: pick first proposal (SOAR uses preference semantics)
        return proposals[0].value  # operator id, e.g. "O1"

    # Phase 4: apply
    def apply_phase(self, operator_id: str) -> str | None:
        name_wmes = self.wm.query(id=operator_id, attr="name")
        if not name_wmes:
            return None
        action = name_wmes[0].value
        self.actions_taken.append(action)
        # Remove the operator from WM after applying
        self.wm.remove("S1", "operator", operator_id)
        return action

    # Phase 5: output
    def output_phase(self) -> list[str]:
        return list(self.actions_taken)

    def decide(self, percepts: dict[str, str]) -> str | None:
        """Run one full decision cycle."""
        self.input_phase(percepts)
        self.elaboration_phase()
        op = self.decision_phase()
        if op is None:
            return self._handle_impasse()
        return self.apply_phase(op)

    def _handle_impasse(self) -> str | None:
        """Universal subgoaling: create a substate to resolve the impasse."""
        # Real SOAR creates a full sub-state on the goal stack.
        # Here we record it and attempt chunking.
        print("Impasse detected — creating subgoal...")
        self._chunk("resolve-impasse")
        return None

    def _chunk(self, name: str) -> None:
        """Chunking: compile subgoal result into a new production."""
        # In real SOAR, chunking traces the dependency graph of the substate
        # and creates a production that compresses the reasoning steps.
        self.chunk_count += 1
        print(f"Chunked new production: chunk-{self.chunk_count} ({name})")


# Demo: blocks-world decision cycle
agent = SOARAgent()
agent.pm.add(Production("propose-move", propose_move, apply_propose))

action = agent.decide({
    "goal": "on-A-B",
    "on":   "A-table",
})
print(f"Action selected: {action}")  # move-A-to-B

class ImpaseName:
    TIE       = "tie"        # multiple equally preferred operators
    NO_CHANGE = "no-change"  # no operator proposed at all
    CONFLICT  = "conflict"   # operators with conflicting preferences
    CONSTRAINT_FAILURE = "constraint-failure"  # preference contradiction


class SubgoalStack:
    """Tracks the goal stack created by universal subgoaling."""

    def __init__(self):
        self._stack: list[dict] = [{"id": "S1", "type": "top-state"}]

    def push(self, impasse_type: str) -> str:
        """Create a new substate to resolve the given impasse."""
        sub_id = f"S{len(self._stack) + 1}"
        self._stack.append({
            "id": sub_id,
            "type": "substate",
            "impasse": impasse_type,
            "superstate": self._stack[-1]["id"],
        })
        print(f"Subgoal created: {sub_id} (resolving {impasse_type} impasse)")
        return sub_id

    def pop(self) -> dict | None:
        """Remove resolved substate and return to superstate."""
        if len(self._stack) <= 1:
            return None
        resolved = self._stack.pop()
        print(f"Subgoal {resolved['id']} resolved — back to {self._stack[-1]['id']}")
        return resolved

    @property
    def depth(self) -> int:
        return len(self._stack)

    @property
    def current(self) -> dict:
        return self._stack[-1]


# Simulate 2-level impasse
stack = SubgoalStack()
stack.push(ImpaseName.NO_CHANGE)
print(f"Stack depth: {stack.depth}")  # 2
stack.pop()
print(f"Stack depth: {stack.depth}")  # 1
